# Base module defining shape abstractions
@abstract
class Shape:
    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

    @virtual
    def describe(self) -> str:
        return "A shape with no specific type"

interface IDrawable:
    def draw(self) -> str: ...

interface ITransformable:
    def scale(self, factor: float) -> None: ...

enum FillStyle:
    SOLID = 0
    GRADIENT = 1
    HATCHED = 2

