# Geometry module implementing shapes with structs and complex types
from shapes import Shape, IDrawable, ITransformable, FillStyle

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return pow(dx * dx + dy * dy, 0.5)

class Rectangle(Shape, IDrawable, ITransformable):
    width: float
    height: float
    origin: Point
    fill: FillStyle

    def __init__(self, w: float, h: float, ox: float, oy: float):
        self.width = w
        self.height = h
        self.origin = Point(ox, oy)
        self.fill = FillStyle.SOLID

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def draw(self) -> str:
        return f"Rectangle({self.origin.x}, {self.origin.y}, {self.width}, {self.height})"

    @override
    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

    @override
    def describe(self) -> str:
        return f"A rectangle with fill={self.fill.name}"

class Circle(Shape, IDrawable):
    center: Point
    radius: float

    def __init__(self, cx: float, cy: float, r: float):
        self.center = Point(cx, cy)
        self.radius = r

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def draw(self) -> str:
        return f"Circle(center=({self.center.x}, {self.center.y}), r={self.radius})"

