# Graphics module with renderer and group management
from shapes import Shape, IDrawable, ITransformable, FillStyle
from geometry import Point, Rectangle, Circle

class ShapeGroup:
    _items: list[Shape]

    def __init__(self):
        self._items = []

    def add(self, shape: Shape) -> None:
        self._items.append(shape)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self._items:
            total = total + shape.area()
        return total

    def total_perimeter(self) -> float:
        total: float = 0.0
        for shape in self._items:
            total = total + shape.perimeter()
        return total

    def count_drawable(self) -> int:
        count: int = 0
        for shape in self._items:
            # Check if shape implements IDrawable
            count = count + 1
        return count

class Renderer:
    @static
    def render_drawing(drawing: IDrawable) -> str:
        return drawing.draw()

    @static
    def scale_shape(shape: ITransformable, factor: float) -> None:
        shape.scale(factor)

def create_sample_shapes() -> tuple[Rectangle, Circle, Rectangle]:
    r1: Rectangle = Rectangle(10.0, 5.0, 0.0, 0.0)
    c: Circle = Circle(5.0, 5.0, 3.0)
    r2: Rectangle = Rectangle(4.0, 6.0, 2.0, 2.0)
    # Configure fills
    r1.fill = FillStyle.HATCHED
    r2.fill = FillStyle.GRADIENT
    return (r1, c, r2)
